$$, $$e6b3fe970f0d7f3f4866df84352c5ef26a87baccef326f45075a4f096493f378$$, $${"A": "a262fef7ff3c850ee7d4c366d01510fd9ac90eb78746739b27731fd838e41795", "D": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "E": "0f4e09fd499cc48287af4073e8a1eb829c614ed9e905e9c2451624d4b5ec6c5b"}$$::jsonb, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$, 491, $$2026-05-07T23:10:02.989896+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0207448F$$, 2027, $$Tactical Data Links (TDLs), as a subset of the broader airborne network, are used in a combat environment to exchange information such as messages, data, radar
tracks, target information, platform status, imagery, and command assignments. TDLs provide interoperability, local and global connectivity, and situational awareness
to the user when operating under rapidly changing operational conditions. TDLs provide a jam-resistant; secure digital data transfer network capability with new and
standardized waveforms and data formats allowing Line-of-Sight (LOS) and Beyond-Line-of-Sight (BLOS) intra-and inter-flight communications. TDLs increase mission
effectiveness, provide positive identification of aircraft in the network, correlate on and off-board sensor data sharing, target, and threat information, and provide the
data link to accomplish time critical targeting and other mission update functions. TDLs are used by all service theater Command and Control (C2) elements, weapons
platforms, and sensors.

 This program provided critical capability and enhancements to the airborne network by supporting common development, integration and interoperability among ground
 and C2 platforms.

 The E-7A program was created to replace the unsustainable E-3 Airborne Warning and Control System (AWACS). The E-3 AWACS, first fielded in the 1970s, is at the
 end of its service life, and costly to maintain. The E-7A was intended to serve as the USAF's principal airborne platform for airborne command and control and airborne
 moving target indicator, providing a reliable, persistent critical node in the long range kill chain for the Joint Force Air Component Commander (JFACC).

 This project funded E-7A advanced communications studies (to include but not limited to hybrid SATCOM, Internet Protocol Beyond Line-of-Sight (IP-BLOS), and
 datalink, analysis, further requirements definition, and software and hardware development and testing. These advanced communication capabilities that may ultimately
 be used on the E-7A or E-3 are required to increase airborne C2 communications resiliency, enabling seamless connectivity with the DAF Battle Network and ensuring
